<template>
  <div class="error-knowledge-container">
    <!-- 页面标题和统计信息 -->
    <header class="page-header">
      <h1 style="display: inline-block; vertical-align: middle">
        错误知识点分析
      </h1>
      <el-button
          type="primary"
          style="margin-left: 1100px; vertical-align: middle"
          @click="fetchAIErrorAnalysis"
      >AI错误点分析</el-button
      >
      <div class="stats">
        <div class="stat-item">
          <span class="stat-value">{{ totalErrors }}</span>
          <span class="stat-label">总错误知识点</span>
        </div>
        <div class="stat-item">
          <span class="stat-value">{{ averageErrorRate }}%</span>
          <span class="stat-label">平均错误率</span>
        </div>
        <div class="stat-item">
          <span class="stat-value">{{ selectedErrors }}</span>
          <span class="stat-label">已选择</span>
        </div>
      </div>
    </header>

    <!-- 主要内容区 -->
    <main class="content-wrapper">
      <!-- 图表分析区 -->
      <section class="chart-section">
        <h2>错误分布分析</h2>
        <div class="chart-container">
          <canvas id="errorDistributionChart"></canvas>
        </div>
        <div class="chart-legend">
          <div
              class="legend-item"
              v-for="(category, index) in categories"
              :key="index"
          >
            <span
                class="legend-color"
                :style="{ backgroundColor: category.color }"
            ></span>
            <span class="legend-text">{{ category.name }}</span>
          </div>
        </div>
      </section>

      <!-- 错误知识点列表 -->
      <section class="errors-list-section">
        <h2>错误知识点列表</h2>
        <div class="list-controls">
          <button class="btn select-all" @click="selectAll">
            {{ allSelected ? "取消全选" : "全选" }}
          </button>
          <button
              class="btn generate-selected"
              @click="generateSelected"
              :disabled="selectedErrors === 0"
          >
            生成选中知识点
          </button>
        </div>

        <!-- 分页控制 -->
        <div class="pagination-controls">
          <div class="items-per-page">
            <label>每页显示: </label>
            <select v-model="itemsPerPage" @change="changeItemsPerPage">
              <option value="3">3条</option>
              <option value="5">5条</option>
              <option value="8">8条</option>
              <option value="10">10条</option>
            </select>
          </div>
        </div>

        <div class="errors-list">
          <div
              class="error-item"
              v-for="(item, index) in paginatedCategories"
              :key="item.id"
              :class="{ selected: item.selected }"
          >
            <div class="error-header">
              <input
                  type="checkbox"
                  v-model="item.selected"
                  class="error-checkbox"
              />
              <div class="error-info">
                <h3 class="error-title">{{ item.name }}</h3>
              </div>
              <button class="detail-btn" @click.stop="showDetail(item)">
                <span class="detail-text">详情</span>
                <svg
                    class="detail-icon"
                    viewBox="0 0 24 24"
                    fill="currentColor"
                >
                  <path d="M9 5l7 7-7 7" />
                </svg>
              </button>
            </div>

            <div class="mastery-control" v-show="item.selected">
              <label class="mastery-label">题目权重: {{ item.weight }}</label>
              <input
                  type="range"
                  min="1"
                  max="11"
                  v-model="item.weight"
                  class="mastery-slider"
              />
            </div>
          </div>
        </div>

        <!-- 分页导航 -->
        <div class="pagination-nav" v-if="totalPages > 1">
          <button
              class="pagination-btn"
              @click="changePage(currentPage - 1)"
              :disabled="currentPage === 1"
          >
            上一页
          </button>

          <button
              class="pagination-btn page-number"
              v-for="page in visiblePages"
              :key="page"
              @click="changePage(page)"
              :class="{ active: page === currentPage }"
          >
            {{ page }}
          </button>

          <button
              class="pagination-btn"
              @click="changePage(currentPage + 1)"
              :disabled="currentPage === totalPages"
          >
            下一页
          </button>
        </div>

        <div class="pagination-info" v-if="totalPages > 0">
          显示
          {{
            paginatedCategories.length > 0
                ? (currentPage - 1) * itemsPerPage + 1
                : 0
          }}-{{ Math.min(currentPage * itemsPerPage, totalErrors) }} 条，共
          {{ totalErrors }} 条
        </div>
      </section>
    </main>

    <!-- 错误详情模态框 -->
    <div v-if="showDetailModal" class="modal-overlay">
      <div class="modal-content">
        <div class="modal-header">
          <h2>{{ currentErrorDetail.title }}</h2>
          <button class="close-btn" @click="closeDetailModal">&times;</button>
        </div>
        <div class="modal-body">
          <p><strong>题目权重:</strong> {{ currentErrorDetail.weight }}</p>
          <p>
            <strong>错误次数:</strong> {{ currentErrorDetail.errorCount }}次
          </p>
          <p>
            <strong>总练习次数:</strong>
            {{ currentErrorDetail.totalAttempts }}次
          </p>
          <p>
            <strong>最近更新时间:</strong>
            {{ currentErrorDetail.lastErrorTime }}
          </p>
          <p>
            <strong>错误原因分析:</strong> {{ currentErrorDetail.errorReason }}
          </p>
          <p><strong>改进建议:</strong> {{ currentErrorDetail.suggestion }}</p>
        </div>
        <div class="modal-footer">
          <button class="btn" @click="closeDetailModal">关闭</button>
        </div>
      </div>
    </div>
    <el-dialog
        v-model="showExamPaper"
        title="生成试卷"
        width="800px"
        :close-on-click-modal="false"
    >
      <ExamPaper
          v-if="showExamPaper"
          :examContent="generatedExamContent"
          :courseId="courseId"
          :chapterId="chapterId"
          :minIds="minIds"
          :maxIds="maxIds"
          @submit="onExamSubmit"
      />
      <template #footer>
        <el-button @click="showExamPaper = false">关闭</el-button>
      </template>
    </el-dialog>
    <el-dialog
