      const match = jsonStrWithIds.match(idsRegex);

      // 使用这两个 const 变量保存结果
      const minIds = match ? parseInt(match[1]) : null;
      const maxIds = match ? parseInt(match[2]) : null;
      // 解析response.data.data，然后生成试卷内容
      const jsonStr = response.data.data
          .replace(/ids:min:\d+,max:\d+$/, "")
          .trim();
      const examData = JSON.parse(jsonStr);
      generatedExamContent.value = generateRealExamContent(examData);
      console.log("解析后", generatedExamContent.value)
      console.log("组卷结果", examData);
    } catch (e) {
      console.error("解析试卷数据失败", e);
      generatedExamContent.value = "试卷数据解析失败";
    }
    console.log("组卷结果", response.data);
  } else {
    showExamPaper.value = true;
    const pointIds = ref([]);
    pointIds.value = selectItem.value.map((item) => ({
      pointIds: item.pointId,
      t: item.weight,
    }));
    const response = await studentService.createTest(
        pointIds.value,
        StringParams
    );
    try {
      // 解析response.data.data，然后生成试卷内容
      const examData = JSON.parse(response.data.data);
      generatedExamContent.value = generateRealExamContent(examData);
      console.log("组卷结果", examData);
    } catch (e) {
      console.error("解析试卷数据失败", e);
      generatedExamContent.value = "试卷数据解析失败";
    }
    console.log("组卷结果", response.data);
  }
};

const generateRealExamContent = (examData) => {
  if (!examData || !examData.questions) return "试卷数据格式错误";

  return examData.questions
      .map((q, idx) => {
        let content = `${idx + 1}. `;

        // 修复内容显示 - 处理含换行符的问题
        const cleanedContent = q.question_content.replace(/\\\\n/g, "\n");

        console.log("out", cleanedContent);

        // 添加多选题支持
        content += `[${
            q.question_type === "single_choice"
                ? "single-choice"
                : q.question_type === "multiple_choice"
                    ? "multiple-choice"
                    : q.question_type === "true_false"
                        ? "true-false"
                        : "fill-in-blank"
        }] ${cleanedContent}\n`;

        // 显示选项（适用于单选、多选和判断题）
        if (q.question_options) {
          q.question_options.forEach((opt) => {
            content += `${opt.label}. ${opt.content}\n`;
          });
        }

        console.log("选项", q.question_options);
        console.log("content", content);

        // 填空题的特殊处理
        if (q.question_type === "fill_blank") {
          const cleanedAnswer = q.correct_answer.replace(/\\\\n/g, "\n");
          content += `答案: ${cleanedAnswer}\n`;
        }
        // 多选题的特殊处理 - 显示多个正确答案
        else if (q.question_type === "multiple_choice") {
          console.log("多选", q.correct_answer);
          // const answerLabels = q.correct_answer.split(',').map(a => a.trim()).join(', ');
          content += `正确答案: ${q.correct_answer}\n`;
        }
        // 其他题型（单选、判断）
        else {
          const cleanedAnswer = q.correct_answer.replace(/\\\\n/g, "\n");
          content += `正确答案: ${cleanedAnswer}\n`;
        }

        // 处理含换行符的解析说明
        const cleanedExplanation = q.explanation.replace(/\\\\n/g, "\n");
        content += `解析: ${cleanedExplanation}\n\n`;

        return content;
      })
      .join("");
};

